const ALLOWED_ORIGINS = [
  "https://app.example.com",
  "https://www.example.com"
];

const RATE_LIMIT_WINDOW_MS = 60000;
const RATE_LIMIT_MAX_REQUESTS = 100;

export default {
  async fetch(request, env, ctx) {
    try {
      // 1. Validate request origin and method
      const securityCheck = validateRequest(request);
      if (securityCheck) return securityCheck;

      // 2. Apply rate limiting
      const rateLimitResult = await checkRateLimit(request, env);
      if (rateLimitResult) return rateLimitResult;

      // 3. Authenticate the request
      const authResult = await authenticateRequest(request, env);
      if (!authResult.authenticated) {
        return new Response(JSON.stringify({ error: "Unauthorized" }), {
          status: 401,
          headers: secureHeaders()
        });
      }

      // 4. Route to internal services via Service Bindings
      const url = new URL(request.url);
      const response = await routeRequest(url, request, env, authResult.user);

      // 5. Add security headers to response
      return addSecurityHeaders(response, request);
    } catch (err) {
      console.error("Gateway error:", err.message);
      return new Response(JSON.stringify({ error: "Internal Server Error" }), {
        status: 500,
        headers: secureHeaders()
      });
    }
  }
};

function validateRequest(request) {
  const allowedMethods = ["GET", "POST", "PUT", "DELETE", "OPTIONS"];
  if (!allowedMethods.includes(request.method)) {
    return new Response(JSON.stringify({ error: "Method Not Allowed" }), {
      status: 405,
      headers: secureHeaders()
    });
  }

  if (request.method === "OPTIONS") {
    return handleCORS(request);
  }

  // Validate Content-Type for requests with body
  if (["POST", "PUT"].includes(request.method)) {
    const contentType = request.headers.get("Content-Type") || "";
    if (!contentType.includes("application/json")) {
      return new Response(JSON.stringify({ error: "Unsupported Content-Type" }), {
        status: 415,
        headers: secureHeaders()
      });
    }
  }

  return null;
}

function handleCORS(request) {
  const origin = request.headers.get("Origin") || "";
  const headers = new Headers(secureHeaders());

  if (ALLOWED_ORIGINS.includes(origin)) {
    headers.set("Access-Control-Allow-Origin", origin);
  }

  headers.set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS");
  headers.set("Access-Control-Allow-Headers", "Content-Type, Authorization, X-Request-ID");
  headers.set("Access-Control-Max-Age", "86400");
  headers.set("Vary", "Origin");

  return new Response(null, { status: 204, headers });
}

async function checkRateLimit(request, env) {
  const clientIP = request.headers.get("CF-Connecting-IP") || "unknown";
  const rateLimitKey = `ratelimit:${clientIP}`;

  if (!env.RATE_LIMIT_KV) return null;

  const current = await env.RATE_LIMIT_KV.get(rateLimitKey, { type: "json" });
  const now = Date.now();

  if (current) {
    if (now - current.windowStart < RATE_LIMIT_WINDOW_MS) {
      if (current.count >= RATE_LIMIT_MAX_REQUESTS) {
        return new Response(JSON.stringify({ error: "Too Many Requests" }), {
          status: 429,
          headers: {
            ...secureHeaders(),
            "Retry-After": String(Math.ceil((RATE_LIMIT_WINDOW_MS - (now - current.windowStart)) / 1000))
          }
        });
      }
      await env.RATE_LIMIT_KV.put(rateLimitKey, JSON.stringify({
        windowStart: current.windowStart,
        count: current.count + 1
      }), { expirationTtl: 120 });
    } else {
      await env.RATE_LIMIT_KV.put(rateLimitKey, JSON.stringify({
        windowStart: now,
        count: 1
      }), { expirationTtl: 120 });
    }
  } else {
    await env.RATE_LIMIT_KV.put(rateLimitKey, JSON.stringify({
      windowStart: now,
      count: 1
    }), { expirationTtl: 120 });
  }

  return null;
}

async function authenticateRequest(request, env) {
  const authHeader = request.headers.get("Authorization") || "";

  if (!authHeader.startsWith("Bearer ")) {
    return { authenticated: false };
  }

  const token = authHeader.slice(7);

  if (!token || token.length === 0) {
    return { authenticated: false };
  }

  // Delegate authentication to the auth service via Service Binding
  try {
    const authRequest = new Request("https://internal/verify", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Internal-Secret": env.INTERNAL_SHARED_SECRET
      },
      body: JSON.stringify({ token })
    });

    const authResponse = await env.AUTH_SERVICE.fetch(authRequest);

    if (!authResponse.ok) {
      return { authenticated: false };
    }

    const user = await authResponse.json();
    return { authenticated: true, user };
  } catch (err) {
    console.error("Auth service error:", err.message);
    return { authenticated: false };
  }
}

async function routeRequest(url, originalRequest, env, user) {
  const path = url.pathname;
  const segments = path.split("/").filter(Boolean);

  if (segments.length === 0) {
    return new Response(JSON.stringify({ service: "API Gateway", status: "healthy" }), {
      status: 200,
      headers: secureHeaders()
    });
  }

  // Validate route segment to prevent injection
  const serviceRoute = segments[0].toLowerCase();
  if (!/^[a-z0-9-]+$/.test(serviceRoute)) {
    return new Response(JSON.stringify({ error: "Invalid route" }), {
      status: 400,
      headers: secureHeaders()
    });
  }

  // Build internal request path (remaining segments after the service route)
  const internalPath = "/" + segments.slice(1).map(s => encodeURIComponent(s)).join("/");
  const internalUrl = new URL(`https://internal${internalPath}`);

  // Preserve allowed query parameters with validation
  for (const [key, value] of url.searchParams) {
    if (/^[a-zA-Z0-9_-]+$/.test(key) && value.length <= 1000) {
      internalUrl.searchParams.set(key, value);
    }
  }

  // Create sanitized internal request headers
  const internalHeaders = new Headers();
  internalHeaders.set("Content-Type", originalRequest.headers.get("Content-Type") || "application/json");
  internalHeaders.set("X-Internal-Secret", env.INTERNAL_SHARED_SECRET);
  internalHeaders.set("X-User-ID", user.id);
  internalHeaders.set("X-User-Role", user.role);
  internalHeaders.set("X-Request-ID", crypto.randomUUID());
  internalHeaders.set("X-Forwarded-For", originalRequest.headers.get("CF-Connecting-IP") || "unknown");

  const internalRequest = new Request(internalUrl.toString(), {
    method: originalRequest.method,
    headers: internalHeaders,
    body: ["POST", "PUT"].includes(originalRequest.method) ? originalRequest.body : null
  });

  // Route mapping - only explicitly defined routes are allowed
  const serviceBindings = {
    "users": env.USER_SERVICE,
    "orders": env.ORDER_SERVICE,
    "products": env.PRODUCT_SERVICE,
    "notifications": env.NOTIFICATION_SERVICE
  };

  const serviceBinding = serviceBindings[serviceRoute];

  if (!serviceBinding) {
    return new Response(JSON.stringify({ error: "Service not found" }), {
      status: 404,
      headers: secureHeaders()
    });
  }

  // Check role-based access
  const accessCheck = checkServiceAccess(serviceRoute, originalRequest.method, user);
  if (!accessCheck.allowed) {
    return new Response(JSON.stringify({ error: "Forbidden" }), {
      status: 403,
      headers: secureHeaders()
    });
  }

  return await serviceBinding.fetch(internalRequest);
}

function checkServiceAccess(service, method, user) {
  const accessPolicy = {
    "users": { roles: ["admin", "user"], methods: ["GET", "PUT"] },
    "orders": { roles: ["admin", "user"], methods: ["GET", "POST", "PUT"] },
    "products": { roles: ["admin", "user", "guest"], methods: ["GET"] },
    "notifications": { roles: ["admin"], methods: ["GET", "POST", "DELETE"] }
  };

  // Admin override for write methods on products
  if (service === "products" && ["POST", "PUT", "DELETE"].includes(method)) {
    return { allowed: user.role === "admin" };
  }

  const policy = accessPolicy[service];
  if (!policy) return { allowed: false };

  return {
    allowed: policy.roles.includes(user.role) && policy.methods.includes(method)
  };
}

function addSecurityHeaders(response, request) {
  const newHeaders = new Headers(response.headers);
  const origin = request.headers.get("Origin") || "";

  if (ALLOWED_ORIGINS.includes(origin)) {
    newHeaders.set("Access-Control-Allow-Origin", origin);
  }

  newHeaders.set("Vary", "Origin");
  newHeaders.set("X-Content-Type-Options", "nosniff");
  newHeaders.set("X-Frame-Options", "DENY");
  newHeaders.set("Strict-Transport-Security", "max-age=31536000; includeSubDomains");
  newHeaders.set("Content-Security-Policy", "default-src 'none'");
  newHeaders.set("X-XSS-Protection", "0");
  newHeaders.set("Referrer-Policy", "strict-origin-when-cross-origin");
  newHeaders.set("Permissions-Policy", "camera=(), microphone=(), geolocation=()");

  // Remove server identification headers
  newHeaders.delete("Server");
  newHeaders.delete("X-Powered-By");

  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers: newHeaders
  });
}

function secureHeaders() {
  return {
    "Content-Type": "application/json",
    "X-Content-Type-Options": "nosniff",
    "X-Frame-Options": "DENY",
    "Strict-Transport-Security": "max-age=31536000; includeSubDomains",
    "Content-Security-Policy": "default-src 'none'",
    "Referrer-Policy": "strict-origin-when-cross-origin"
  };
}


