export class UserService {
  constructor(env) {
    this.env = env;
  }

  async fetch(request) {
    try {
      if (!this.verifyInternalCaller(request)) {
        return new Response(JSON.stringify({ error: "Forbidden" }), {
          status: 403,
          headers: { "Content-Type": "application/json" }
        });
      }

      const url = new URL(request.url);
      const userId = request.headers.get("X-User-ID");
      const userRole = request.headers.get("X-User-Role");
      const requestId = request.headers.get("X-Request-ID");

      if (!userId || !userRole) {
        return new Response(JSON.stringify({ error: "Missing user context" }), {
          status: 400,
          headers: { "Content-Type": "application/json" }
        });
      }

      const path = url.pathname;

      // GET /profile - Get current user's profile
      if (path === "/profile" && request.method === "GET") {
        return await this.getProfile(userId, requestId);
      }

      // PUT /profile - Update current user's profile
      if (path === "/profile" && request.method === "PUT") {
        return await this.updateProfile(userId, request, requestId);
      }

      // GET /:id - Admin only: get any user's profile
      const userIdMatch = path.match(/^\/([a-zA-Z0-9-]+)$/);
      if (userIdMatch && request.method === "GET") {
        const targetUserId = userIdMatch[1];

        // Authorization: users can only access their own profile, admins can access any
        if (userRole !== "admin" && targetUserId !== userId) {
          return new Response(JSON.stringify({ error: "Forbidden" }), {
            status: 403,
            headers: { "Content-Type": "application/json" }
          });
        }

        return await this.getProfile(targetUserId, requestId);
      }

      return new Response(JSON.stringify({ error: "Not Found" }), {
        status: 404,
        headers: { "Content-Type": "application/json" }
      });
    } catch (err) {
      console.error("User service error:", err.message);
      return new Response(JSON.stringify({ error: "Internal Error" }), {
        status: 500,
        headers: { "Content-Type": "application/json" }
      });
    }
  }

  verifyInternalCaller(request) {
    const secret = request.headers.get("X-Internal-Secret");
    if (!secret || !this.env.INTERNAL_SHARED_SECRET) return false;
    return timingSafeEqual(secret, this.env.INTERNAL_SHARED_SECRET);
  }

  async getProfile(userId, requestId) {
    if (!this.env.USER_KV) {
      return new Response(JSON.stringify({ error: "Service unavailable" }), {
        status: 503,
        headers: { "Content-Type": "application/json" }
      });
    }

    // Validate userId format
    if (!/^[a-zA-Z0-9-]+$/.test(userId)) {
      return new Response(JSON.stringify({ error: "Invalid user ID" }), {
        status: 400,
        headers: { "Content-Type": "application/json" }
      });
    }

    const userData = await this.env.USER_KV.get(`user:${userId}`, { type: "json" });

    if (!userData) {
      return new Response(JSON.stringify({ error: "User not found" }), {
        status: 404,
        headers: { "Content-Type": "application/json" }
      });
    }

    // Strip sensitive fields before returning
    const { passwordHash, internalNotes, ...safeUserData } = userData;

    return new Response(JSON.stringify({
      ...safeUserData,
      requestId
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" }
    });
  }

  async updateProfile(userId, request, requestId) {
    if (!this.env.USER_KV) {
      return new Response(JSON.stringify({ error: "Service unavailable" }), {
        status: 503,
        headers: { "Content-Type": "application/json" }
      });
    }

    // Validate userId format
    if (!/^[a-zA-Z0-9-]+$/.test(userId)) {
      return new Response(JSON.stringify({ error: "Invalid user ID" }), {
        status: 400,
        headers: { "Content-Type": "application/json" }
      });
    }

    let body;
    try {
      body = await request.json();
    } catch {
      return new Response(JSON.stringify({ error: "Invalid JSON body" }), {
        status: 400,
        headers: { "Content-Type": "application/json" }
      });
    }

    // Whitelist allowed update fields - prevent privilege escalation
    const allowedFields = ["displayName", "bio", "avatarUrl", "preferences"];
    const sanitizedUpdate = {};

    for (const field of allowedFields) {
      if (body[field] !== undefined) {
        // Basic input validation
        if (typeof body[field] === "string" && body[field].length > 5000) {
          return new Response(JSON.stringify({ error: `Field ${field} exceeds maximum length` }), {
            status: 400,
            headers: { "Content-Type": "application/json" }
          });
        }
        sanitizedUpdate[field] = body[field];
      }
    }

    if (Object.keys(sanitizedUpdate).length === 0) {
      return new Response(JSON.stringify({ error: "No valid fields to update" }), {
        status: 400,
        headers: { "Content-Type": "application/json" }
      });
    }

    const existingData = await this.env.USER_KV.get(`user:${userId}`, { type: "json" });

    if (!existingData) {
      return new Response(JSON.stringify({ error: "User not found" }), {
        status: 404,
        headers: { "Content-Type": "application/json" }
      });
    }

    const updatedData = {
      ...existingData,
      ...sanitizedUpdate,
      updatedAt: new Date().toISOString()
    };

    await this.env.USER_KV.put(`user:${userId}`, JSON.stringify(updatedData));

    const { passwordHash, internalNotes, ...safeUserData } = updatedData;

    return new Response(JSON.stringify({
      ...safeUserData,
      requestId
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" }
    });
  }
}

